local shellcode

poops_version_string = "Poops 2.0"

local ERR_TRIPLE_FREE = 2
local ERR_LEAK_KQUEUE = 3

local err_strings = {
    [ERR_TRIPLE_FREE] = "Triple free failed - reboot and retry",
    [ERR_LEAK_KQUEUE] = "Kqueue leak failed - reboot and retry"
}
    
function poops()
    send_notification(poops_version_string)
    
    if not TITLE_ID then
        error("Update Luac0re to at least 2.3 version")
    end
    
    if PLATFORM ~= "PS5" then
        send_notification("Unsupported platform  " .. PLATFORM)
        return
    end
    
    if tonumber(FW_VERSION) < 4.03 or tonumber(FW_VERSION) > 12.00 then
        send_notification("Unsupported fw " .. FW_VERSION)
        return
    end

    if is_jailbroken() then
        send_notification("Already Jailbroken")
        return
    end

    local failcheck_path = "/" .. get_nidpath() .. "/common_temp/luac0re.fail"
    if file_exists(failcheck_path) then
        send_notification("Restart your PS5 to run exploit again");
        return
    end
    
    file_write(failcheck_path, "")
    
    if not sceKernelDlsym then
        init_dlsym()
    end
    
    write_shellcode(SHELLCODE_BASE, shellcode)
    
    local func_shellcode = func_wrap(SHELLCODE_BASE)
    
    local arg1 = malloc(16)
    write64(arg1,     EBOOT_BASE)
    write64(arg1 + 8, SCE_KERNEL_DLSYM)
    
    local logsock_fd = -1
    
    if log_sock and log_sock >= 0 then
        logsock_fd = log_sock
    end
    
    if not LOG_SERVER then
        LOG_SERVER = "127.0.0.2"
    end
    
    local sock_count = 80
    local sock_array = malloc(sock_count * 4)
    for i = 0, sock_count - 1 do
        local fd = create_socket(AF_INET6, SOCK_STREAM, 0)
        if fd < 0 then
            error(string.format("create_socket failed at index %d", i))
        end
    
        local offset = i * 4
        write32(sock_array + offset, fd)
    end
    
    local ret = func_shellcode(arg1, logsock_fd, LOG_SERVER, TITLE_ID, sock_array)
    if ret == 0 then
        send_notification("Jailbreak success")
        local current_ip = get_current_ip()
    
        if current_ip then
            local lua_network_str = string.format("%s:%d", current_ip, 9026)
            local elf_network_str = string.format("%s:%d", current_ip, 9021)
            show_dialog(string.format("%s\n%s\nPlatform: %s\nFW: %s\nRemote Lua Loader\nListening: %s\nELF Loader\nListening: %s",
                version_string, poops_version_string, PLATFORM, FW_VERSION, lua_network_str, elf_network_str))
        else
            show_dialog("Jailbreak success but network not found")
        end
    else
        local msg = err_strings[ret]
        if msg then
            send_notification(msg)
        else
            send_notification("Unknown error: " .. tostring(ret))
        end
    end

end

shellcode = ""

poops()
